import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String s = br.readLine();
            if (s == null) break;
            int day = Integer.parseInt(s.trim());
            switch (day) {
                case 1: sb.append("Monday\n"); break;
                case 2: sb.append("Tuesday\n"); break;
                case 3: sb.append("Wednesday\n"); break;
                case 4: sb.append("Thursday\n"); break;
                case 5: sb.append("Friday\n"); break;
                case 6: sb.append("Saturday\n"); break;
                case 7: sb.append("Sunday\n"); break;
                default: sb.append("Invalid day number\n");
            }
        }
        System.out.print(sb.toString());
    }
}

