import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        if idx >= len(data):
            break
        day = int(data[idx]); idx += 1
        if day == 1:
            out.append('Monday')
        elif day == 2:
            out.append('Tuesday')
        elif day == 3:
            out.append('Wednesday')
        elif day == 4:
            out.append('Thursday')
        elif day == 5:
            out.append('Friday')
        elif day == 6:
            out.append('Saturday')
        elif day == 7:
            out.append('Sunday')
        else:
            out.append('Invalid day number')
    sys.stdout.write('\n'.join(out))

if __name__ == '__main__':
    main()

